  /**
   * Size of the generated image (e.g. "256x256", "512x512").
   * If not set, the model uses its default size.
   */
  size?: string;

  /**
   * The visual style to apply to the generated image.
   * - "pixel" for a classic pixel art look
   * - "retro" for a retro/vintage style
   * - "8bit" for an 8-bit video game aesthetic
   */
