### 10. `packages/pixelart/src/pixelart-image-model.ts`

Core model class implementing `ImageModelV3`. Uses `postJsonToApi` from `@ai-sdk/provider-utils` to call `POST /images/generate`. Parses provider-specific options from `providerOptions.pixelart` via `parseProviderOptions` + a Zod schema. Returns base64-encoded images.

Key design decisions:
- `maxImagesPerCall = 4` (reasonable fictional limit)
- Warns if `aspectRatio` is passed (unsupported — this API uses `size` instead)
- Warns if `seed` is passed (unsupported)
- Passes `size` from standard call options through to the API body (overridable by the `size` in provider settings)
- Passes `style` and `pixelDensity` from parsed provider options to the API body
- Error responses use `createJsonErrorResponseHandler` with a minimal Zod schema
- Response schema expects `{ data: [{ b64_json: string }] }`

```typescript
import { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  InferSchema,
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  lazySchema,
  parseProviderOptions,
  postJsonToApi,
  zodSchema,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import { PixelArtImageModelId, PixelArtImageSettings } from './pixelart-image-settings';

interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers: () => Record<string, string | undefined>;
  fetch?: typeof fetch;
  _internal?: { currentDate?: () => Date };
}

// Zod schema for provider-specific options
const pixelArtImageSettingsSchema = lazySchema(() =>
  zodSchema(
    z.object({
      size: z.string().optional(),
      style: z.enum(['pixel', 'retro', '8bit']).optional(),
      pixelDensity: z.number().positive().optional(),
    }),
  ),
);

export type PixelArtImageModelOptions = InferSchema<typeof pixelArtImageSettingsSchema>;

// Response schema from PixelArt API
const pixelArtImageResponseSchema = lazySchema(() =>
  zodSchema(
    z.object({
      created: z.number().nullish(),
      data: z.array(
        z.object({
          b64_json: z.string(),
        }),
      ),
    }),
  ),
);

// Error schema
const pixelArtErrorSchema = z.object({
  error: z.object({
    message: z.string(),
    code: z.union([z.string(), z.number()]).nullish(),
  }),
});

const pixelArtFailedResponseHandler = createJsonErrorResponseHandler({
  errorSchema: pixelArtErrorSchema,
  errorToMessage: data => data.error.message,
});

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3';
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate({
    prompt,
    n,
    size,
    aspectRatio,
    seed,
    providerOptions,
    headers,
    abortSignal,
  }: Parameters<ImageModelV3['doGenerate']>[0]): Promise<
    Awaited<ReturnType<ImageModelV3['doGenerate']>>
  > {
    const warnings: Array<SharedV3Warning> = [];

    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details: 'PixelArt does not support aspectRatio. Use `size` instead.',
      });
    }
    if (seed != null) {
      warnings.push({ type: 'unsupported', feature: 'seed' });
    }

    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageSettingsSchema,
    });

    const currentDate = this.config._internal?.currentDate?.() ?? new Date();

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(this.config.headers(), headers),
      body: {
        model: this.modelId,
        prompt,
        n,
        size: pixelArtOptions?.size ?? size,
        style: pixelArtOptions?.style,
        pixel_density: pixelArtOptions?.pixelDensity,
        response_format: 'b64_json',
      },
      failedResponseHandler: pixelArtFailedResponseHandler,
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtImageResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    return {
      images: response.data.map(item => item.b64_json),
      warnings,
      response: {
        timestamp: currentDate,
        modelId: this.modelId,
        headers: responseHeaders,
      },
      providerMetadata: {
        pixelart: {
          images: response.data.map(() => ({
            created: response.created ?? undefined,
          })),
        },
      },
    };
  }
}
```

### 11. `packages/pixelart/src/pixelart-provider.ts`

Provider factory. Implements `ProviderV3`. Throws `NoSuchModelError` for `languageModel` and `embeddingModel`.

```typescript
import { ImageModelV3, NoSuchModelError, ProviderV3 } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import { PixelArtImageModel } from './pixelart-image-model';
import { PixelArtImageModelId } from './pixelart-image-settings';
import { VERSION } from './version';

export interface PixelArtProviderSettings {
  /** API key. Defaults to PIXELART_API_KEY env var. */
  apiKey?: string;
  /** Base URL. Defaults to https://api.pixelart.ai/v1 */
  baseURL?: string;
  /** Custom headers. */
  headers?: Record<string, string>;
  /** Custom fetch implementation. */
  fetch?: FetchFunction;
}

export interface PixelArtProvider extends ProviderV3 {
  image(modelId: PixelArtImageModelId): ImageModelV3;
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
  /** @deprecated Use `embeddingModel` instead. */
  textEmbeddingModel(modelId: string): never;
}

const defaultBaseURL = 'https://api.pixelart.ai/v1';

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL =
    withoutTrailingSlash(options.baseURL) ?? defaultBaseURL;

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (modelId: PixelArtImageModelId) =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const embeddingModel = (modelId: string): never => {
    throw new NoSuchModelError({ modelId, modelType: 'embeddingModel' });
  };

  return {
    specificationVersion: 'v3',
    imageModel: createImageModel,
    image: createImageModel,
    languageModel: (modelId: string) => {
      throw new NoSuchModelError({ modelId, modelType: 'languageModel' });
    },
    embeddingModel,
    textEmbeddingModel: embeddingModel,
  };
}

export const pixelart = createPixelArt();
```

