import type { ImageModelV3, SharedV3Warning } from '@ai-sdk/provider';
import {
  combineHeaders,
  createJsonErrorResponseHandler,
  createJsonResponseHandler,
  parseProviderOptions,
  postJsonToApi,
  resolve,
} from '@ai-sdk/provider-utils';
import { z } from 'zod/v4';
import type { PixelArtImageModelId } from './pixelart-image-settings';

// ---------------------------------------------------------------------------
// Provider options schema (validated Zod schema for pixelart-specific params)
// ---------------------------------------------------------------------------

const pixelArtImageProviderOptionsSchema = z.object({
  /**
   * Output image size, e.g. "512x512". Takes precedence over the standard
   * SDK `size` parameter when both are supplied.
   */
  size: z.string().optional(),

  /**
   * Visual rendering style.
   */
  style: z.enum(['pixel', 'retro', '8bit']).optional(),

  /**
   * Pixel density (dots per grid unit). Must be a positive number.
   */
  pixelDensity: z.number().positive().optional(),
});

export type PixelArtImageModelOptions = z.infer<
  typeof pixelArtImageProviderOptionsSchema
>;

// ---------------------------------------------------------------------------
// Config passed from the provider factory to the model
// ---------------------------------------------------------------------------

export interface PixelArtImageModelConfig {
  provider: string;
  baseURL: string;
  headers?: () => Record<string, string | undefined>;
  fetch?: typeof globalThis.fetch;
}

// ---------------------------------------------------------------------------
// API response schema
// ---------------------------------------------------------------------------

const pixelArtApiResponseSchema = z.object({
  data: z.array(
    z.object({
      b64_json: z.string().optional(),
      url: z.string().optional(),
    }),
  ),
  model: z.string().optional(),
});

// ---------------------------------------------------------------------------
// Image model implementation
// ---------------------------------------------------------------------------

export class PixelArtImageModel implements ImageModelV3 {
  readonly specificationVersion = 'v3' as const;
  readonly maxImagesPerCall = 4;

  get provider(): string {
    return this.config.provider;
  }

  constructor(
    readonly modelId: PixelArtImageModelId,
    private readonly config: PixelArtImageModelConfig,
  ) {}

  async doGenerate(
    options: Parameters<ImageModelV3['doGenerate']>[0],
  ): Promise<Awaited<ReturnType<ImageModelV3['doGenerate']>>> {
    const {
      prompt,
      n,
      size: sdkSize,
      aspectRatio,
      seed,
      providerOptions,
      headers,
      abortSignal,
    } = options;

    const warnings: Array<SharedV3Warning> = [];

    // Warn about unsupported standard options
    if (aspectRatio != null) {
      warnings.push({
        type: 'unsupported',
        feature: 'aspectRatio',
        details:
          'The PixelArt provider does not support aspectRatio. Use the size option instead.',
      });
    }

    // Parse and validate provider-specific options
    const pixelArtOptions = await parseProviderOptions({
      provider: 'pixelart',
      providerOptions,
      schema: pixelArtImageProviderOptionsSchema,
    });

    // Provider option `size` takes precedence over the standard SDK `size`
    const resolvedSize = pixelArtOptions?.size ?? sdkSize;

    // Build the request body
    const body: Record<string, unknown> = {
      model: this.modelId,
      prompt,
      n,
    };

    if (resolvedSize != null) {
      body.size = resolvedSize;
    }
    if (seed != null) {
      body.seed = seed;
    }
    if (pixelArtOptions?.style != null) {
      body.style = pixelArtOptions.style;
    }
    if (pixelArtOptions?.pixelDensity != null) {
      body.pixel_density = pixelArtOptions.pixelDensity;
    }

    // Always request base64 output for reliable cross-environment handling
    body.response_format = 'b64_json';

    const resolvedHeaders = await resolve(this.config.headers?.());

    const { value: response, responseHeaders } = await postJsonToApi({
      url: `${this.config.baseURL}/images/generate`,
      headers: combineHeaders(resolvedHeaders, headers),
      body,
      failedResponseHandler: createJsonErrorResponseHandler({
        errorSchema: z.object({
          error: z.object({
            message: z.string(),
            type: z.string().optional(),
            code: z.string().optional(),
          }),
        }),
        errorToMessage: data => data.error.message,
      }),
      successfulResponseHandler: createJsonResponseHandler(
        pixelArtApiResponseSchema,
      ),
      abortSignal,
      fetch: this.config.fetch,
    });

    // Convert base64 strings → Uint8Array buffers
    const images: Array<Uint8Array> = response.data.map(item => {
      if (item.b64_json) {
        const binaryString = atob(item.b64_json);
        const bytes = new Uint8Array(binaryString.length);
        for (let i = 0; i < binaryString.length; i++) {
          bytes[i] = binaryString.charCodeAt(i);
        }
        return bytes;
      }
      throw new Error(
        'PixelArt API returned an image without b64_json data. ' +
          'Ensure the API key is valid and the model supports image generation.',
      );
    });

    return {
      images,
      warnings,
      providerMetadata: {
        pixelart: {
          images: response.data,
        },
      },
      response: {
        timestamp: new Date(),
        modelId: response.model ?? this.modelId,
        headers: responseHeaders,
      },
    };
  }
}

