import type { ImageModelV3, ProviderV3 } from '@ai-sdk/provider';
import { NoSuchModelError } from '@ai-sdk/provider';
import type { FetchFunction } from '@ai-sdk/provider-utils';
import {
  loadApiKey,
  withoutTrailingSlash,
  withUserAgentSuffix,
} from '@ai-sdk/provider-utils';
import type { PixelArtImageModelId } from './pixelart-image-settings';
import { PixelArtImageModel } from './pixelart-image-model';
import { VERSION } from './version';

// ---------------------------------------------------------------------------
// Provider settings
// ---------------------------------------------------------------------------

export interface PixelArtProviderSettings {
  /**
   * PixelArt API key. Defaults to the `PIXELART_API_KEY` environment variable.
   */
  apiKey?: string;

  /**
   * Base URL for the PixelArt API.
   * Defaults to `https://api.pixelart.ai/v1`.
   */
  baseURL?: string;

  /**
   * Custom HTTP headers included in every request.
   */
  headers?: Record<string, string>;

  /**
   * Custom fetch implementation (useful for testing or proxying).
   */
  fetch?: FetchFunction;
}

// ---------------------------------------------------------------------------
// Provider interface
// ---------------------------------------------------------------------------

export interface PixelArtProvider extends ProviderV3 {
  /**
   * Create a PixelArt image model by model ID.
   */
  image(modelId: PixelArtImageModelId): ImageModelV3;

  /**
   * Alias for `image()` — follows the standard SDK provider convention.
   */
  imageModel(modelId: PixelArtImageModelId): ImageModelV3;
}

// ---------------------------------------------------------------------------
// Factory function
// ---------------------------------------------------------------------------

const DEFAULT_BASE_URL = 'https://api.pixelart.ai/v1';

export function createPixelArt(
  options: PixelArtProviderSettings = {},
): PixelArtProvider {
  const baseURL = withoutTrailingSlash(options.baseURL ?? DEFAULT_BASE_URL);

  const getHeaders = () =>
    withUserAgentSuffix(
      {
        Authorization: `Bearer ${loadApiKey({
          apiKey: options.apiKey,
          environmentVariableName: 'PIXELART_API_KEY',
          description: 'PixelArt',
        })}`,
        ...options.headers,
      },
      `ai-sdk/pixelart/${VERSION}`,
    );

  const createImageModel = (
    modelId: PixelArtImageModelId,
  ): PixelArtImageModel =>
    new PixelArtImageModel(modelId, {
      provider: 'pixelart.image',
      baseURL: baseURL ?? DEFAULT_BASE_URL,
      headers: getHeaders,
      fetch: options.fetch,
    });

  const provider: PixelArtProvider = {
    specificationVersion: 'v3',

    image: createImageModel,
    imageModel: createImageModel,

    languageModel(modelId: string) {
      throw new NoSuchModelError({
        modelId,
        modelType: 'languageModel',
        message:
          'The PixelArt provider only supports image generation. ' +
          `No language model "${modelId}" is available.`,
      });
    },

    embeddingModel(modelId: string) {
      throw new NoSuchModelError({
        modelId,
        modelType: 'embeddingModel',
        message:
          'The PixelArt provider only supports image generation. ' +
          `No embedding model "${modelId}" is available.`,
      });
    },
  };

  return provider;
}

/**
 * Default PixelArt provider instance.
 * Reads the API key from the `PIXELART_API_KEY` environment variable.
 */
